import {SpotterMainApp} from "../type";
import {NetProxyOptions, proxy as  networkProxy, unproxy} from "./hijack";

export interface NetworkSystemOptions {
    proxy: NetProxyOptions
}

export function boostrapNetworkSystem(options: NetworkSystemOptions, sptApp: SpotterMainApp ) {
    sptApp.network = {} as any
    /**
     * Network proxy
     */
    networkProxy(options.proxy)
    sptApp.network.unproxy = unproxy
}
